mapper.select:
        SELECT cartSeq 
        FROM userCart uc
        WHERE uc.userSeq = (
                           SELECT userSeq 
                           FROM user 
                           WHERE userId = #{userId}
                        )
            AND uc.productSeq = #{productSeq}
	        AND uc.materialSeq = #{materialSeq}


                    AND uc.productSizeSeq IS NULL


                    AND uc.productSizeSeq = #{productSizeSeq}

SELECT quantity
FROM stock
WHERE productSeq = #{productSeq}
